fun solve(points: Array<Array<Long>>): Long {
    val n = points.size
    if (n < 4) return 0L

    var res = 0L

    for (i in 0 until n) {
        val slopeMap = mutableMapOf<Pair<Long, Long>, MutableSet<Pair<Long, Long>>>()
        for (j in 0 until n) {
            if (i == j) continue
            var dx = points[j][0] - points[i][0]
            var dy = points[j][1] - points[i][1]
            if (dx == 0L && dy == 0L) continue

            val g = gcd(dx, dy)
            if (g != 0L) {
                dx /= g
                dy /= g
            }
            val key = normalizeSlope(dx, dy)
            slopeMap.getOrPut(key) { mutableSetOf() }.add(points[j][0] to points[j][1])
        }

        for ((_, set) in slopeMap) {
            val cnt = set.size.toLong()
            if (cnt >= 3) {
                res += cnt * (cnt - 1) * (cnt - 2) / 6
            }
        }
    }

    val total = n.toLong() * (n - 1).toLong() * (n - 2).toLong() * (n - 3).toLong() / 24
    return total - res
}

private fun gcd(a: Long, b: Long): Long {
    var x = abs(a)
    var y = abs(b)
    while (y != 0L) {
        val temp = y
        y = x % y
        x = temp
    }
    return x
}

